package ua.university.sms.model.entity;
import jakarta.persistence.*;import java.time.LocalDateTime;
@Entity @Table(name="enrollments",uniqueConstraints=@UniqueConstraint(columnNames={"student_id","course_id"})) public class Enrollment{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@ManyToOne(optional=false) @JoinColumn(name="student_id") private Student student;@ManyToOne(optional=false) @JoinColumn(name="course_id") private Course course;@Column(nullable=false) private boolean paid;private Double grade;@Column(name="enrolled_at",nullable=false) private LocalDateTime enrolledAt=LocalDateTime.now(); public Long getId(){return id;}public Student getStudent(){return student;}public void setStudent(Student student){this.student=student;}public Course getCourse(){return course;}public void setCourse(Course course){this.course=course;}public boolean isPaid(){return paid;}public void setPaid(boolean paid){this.paid=paid;}public Double getGrade(){return grade;}public void setGrade(Double grade){this.grade=grade;}public LocalDateTime getEnrolledAt(){return enrolledAt;}public void setEnrolledAt(LocalDateTime enrolledAt){this.enrolledAt=enrolledAt;}}
